<?php require_once 'includes/header.php'; $lang=current_lang(); $l=['ar'=>'ar','fr'=>'fr','en'=>'en'][$lang]??'ar'; try{$items=db()->query("SELECT id,slug,COALESCE(NULLIF(title_{$l},''),title_ar) AS t,COALESCE(NULLIF(body_{$l},''),body_ar) AS b,featured_image FROM content_items WHERE type='video' AND status='published' ORDER BY created_at DESC")->fetchAll();}catch(Exception$e){$items=[];} ?>
<main id="main-content"><div class="page-hero"><div class="max-w-4xl mx-auto px-4"><h1><span aria-hidden="true">🎥</span> <?= __('nav_videos',$lang) ?></h1></div></div>
<section class="py-8 relative z-10"><div class="max-w-7xl mx-auto px-4"><?php if(empty($items)):?><div class="empty-state"><div class="empty-state-icon" aria-hidden="true">🎥</div><p><?= __('no_results',$lang)?></p></div><?php else:?><div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"><?php foreach($items as $i):?><div class="glass-card p-4"><?php if(preg_match('/youtube\.com\/embed\/([a-zA-Z0-9_-]+)/',$i['b'],$m)||preg_match('/youtu\.be\/([a-zA-Z0-9_-]+)/',$i['b'],$m)):?><div class="aspect-video rounded-lg overflow-hidden mb-3"><iframe src="https://www.youtube.com/embed/<?= e($m[1])?>" class="w-full h-full" frameborder="0" allowfullscreen title="<?= e($i['t'])?>"></iframe></div><?php else:?><div class="aspect-video rounded-lg mb-3 bg-emerald-900/30 flex items-center justify-center text-4xl" aria-hidden="true">🎥</div><?php endif;?><h3 class="font-semibold text-white"><?= e($i['t'])?></h3></div><?php endforeach;?></div><?php endif;?></div></section></main>
<?php include 'includes/footer.php';?>